rule"Evaluation: Graylog Monitoring - Self 001"

when
    contains(to_string($message.image_name),"datanode")

then
    let mylog = grok(
        value: to_string($message.message),
        pattern: "\\[%{TIMESTAMP_ISO8601:event_created}\\]%{SPACE}\\[%{WORD:event_severity}%{SPACE}\\]%{SPACE}\\[%{SPACE}%{GREEDYDATA:application_component}%{SPACE}\\]%{SPACE}\\[%{SPACE}%{HOSTNAME:event_source}%{SPACE}\\]%{GREEDYDATA:message}"
    );

    set_fields(mylog);

    rename_field(
        old_field: "created",
        new_field: "container_created"
    );

    remove_multiple_fields(
        pattern: "[A-Z0-9_-]+",
        names: ["container_id","image_id","tag"]
    );
end

rule"Evaluation: Graylog Monitoring - Self 004"

when
    contains(to_string($message.image_name),"mongo")
    //true
then

    let mylog = flatten_json(to_string(parse_json(replace(to_string($message.message),"$"))),"flatten",true);

    set_fields(to_map(mylog));

    rename_field("attr_message_msg","message");
    rename_field("attr_message_verbose_level","event_severity");
    rename_field("attr_message_session_name","application_component");
    rename_field("t_date","event_created");
    rename_field("created","container_created");

    remove_multiple_fields(
        pattern: "attr_[A-Za-z-_]*",
        names: ["c","container_id","ctx","id","image_id","msg","s","tag"]
    );
end

rule"Evaluation: Graylog Monitoring - Self 002"

when
    contains(to_string($message.image_name),"graylog")
    //true

then
    let mylog = grok(
        value: to_string($message.message),
        pattern: "%{TIMESTAMP_ISO8601}%{SPACE}%{WORD:event_severity}%{SPACE}:%{SPACE}%{NOTSPACE:application_component}%{SPACE}-%{SPACE}%{GREEDYDATA:message}",
        only_named_captures: true
    );

    set_fields(mylog);

    let eventcreated = regex_replace(
        value: to_string($message.message),
        pattern: "^([0-9\\-]+?)\\s([0-9:]+?),",
        replacement: "$1T$2"
    );

    set_field(
        value: to_date(eventcreated),
        field: "event_created"
    );

    rename_field(
        old_field: "created",
        new_field: "container_created"
    );

    remove_multiple_fields(
        pattern: "[A-Z0-9_-]+",
        names: ["container_id","image_id","tag"]
    );

end

rule"Evaluation: Graylog Monitoring - Self 003"

when
    contains(to_string($message.message),"GRAYLOG-") 
    //true

then
    let mylog = grok(
        value: to_string($message.message),
        pattern: "%{TIMESTAMP_ISO8601}%{SPACE}%{HOSTNAME:event_source}%{SPACE}%{DATA:application_component}:%{SPACE}\\[%{WORD:event_severity}\\]%{SPACE}-%{SPACE}%{GREEDYDATA:message}"
    );

    set_fields(mylog);
    remove_multiple_fields(
        pattern: "[A-Z0-9_-]+"
    );
    //set_field("touched",true);

end

rule "Evaluation: Reverse Name Resolution - source_ip"
when
    has_field("source_ip") 
    && ! has_field("source_hostname")

then
    let source_hostname = lookup_value(
        lookup_table: "evaluation-reverse-name-resolution", 
        key: to_string($message.source_ip)
        );

    let source_hostname = regex_replace(
        pattern: "(.*?)\\.$", 
        value: to_string(source_hostname),
        replacement: "$1"
        );

    set_field("source_hostname", to_string(source_hostname));

end

rule "Evaluation: Spamhaus Drop List - destination_ip"
when
    has_field("destination_ip") 
    && ! contains(to_string($message.gim_tags), "destination_is_internal") 
    && lookup_value("spamhaus-drop", to_string($message.destination_ip)).single_value == true

then
    set_field("spamhaus_flag", true);

    let lookup_result = lookup("spamhaus-drop", to_string($message.destination_ip));
    set_field("spamhaus_sbl_id", lookup_result.multi_value.sbl_id);
    set_field("spamhaus_subnet", lookup_result.multi_value.subnet);

end

